import { createBrowserRouter, Outlet } from 'react-router';
import { Landing } from './pages/Home';
import { About } from './pages/About';
import { Features } from './pages/Features';
import { Contact } from './pages/Contact';
import { PrivacyPolicy } from './pages/PrivacyPolicy';
import { TermsOfService } from './pages/TermsOfService';
import { Register } from './pages/Register';
import { Login } from './pages/Login';
import { LoginForm } from './pages/LoginForm';
import { DashboardLayout } from './components/DashboardLayout';
import { PatientDashboard } from './pages/patient/Dashboard';
import { HealthLog } from './pages/patient/HealthLog';
import { Appointments } from './pages/patient/Appointments';
import { Profile } from './pages/patient/Profile';
import { HospitalFinder } from './pages/patient/HospitalFinder';
import { LabResults } from './pages/patient/LabResults';
import { Messages } from './pages/Messages';
import { ProfessionalDashboard } from './pages/professional/Dashboard';
import { PatientDetail } from './pages/professional/PatientDetail';
import { PatientWorkspace } from './pages/professional/PatientWorkspace';
import { DoctorPatients } from './pages/professional/DoctorPatients';
import { DoctorSchedule } from './pages/professional/DoctorSchedule';
import { DoctorReports } from './pages/professional/DoctorReports';
import { NursePatients } from './pages/professional/NursePatients';
import { NurseRounds } from './pages/professional/NurseRounds';
import { NursePatientCare } from './pages/professional/NursePatientCare';
import { HospitalDashboard } from './pages/hospital/HospitalDashboard';
import { LabManagement } from './pages/hospital/LabManagement';
import { NotFound } from './pages/NotFound';
import { ScrollToTopOnNavigate } from './components/ScrollToTopOnNavigate';
import { CURRENT_USER_PATIENT, CURRENT_USER_DOCTOR } from './lib/mockData';

function RootLayout() {
  return (
    <>
      <ScrollToTopOnNavigate />
      <Outlet />
    </>
  );
}

export const router = createBrowserRouter([
  {
    path: '/',
    Component: RootLayout,
    errorElement: <NotFound />,
    children: [
      { index: true, Component: Landing },
      { path: 'about', Component: About },
      { path: 'features', Component: Features },
      { path: 'contact', Component: Contact },
      { path: 'privacy', Component: PrivacyPolicy },
      { path: 'terms', Component: TermsOfService },
      { path: 'register', Component: Register },
      { path: 'login', Component: Login },
      { path: 'login/:role', Component: LoginForm },

      // ─── Patient ───────────────────────────────────────────────────────────
      {
        path: 'patient',
        element: <DashboardLayout role="patient" userName={CURRENT_USER_PATIENT.name} />,
        children: [
          { index: true, Component: PatientDashboard },
          { path: 'dashboard', Component: PatientDashboard },
          { path: 'log', Component: HealthLog },
          { path: 'appointments', Component: Appointments },
          { path: 'hospitals', Component: HospitalFinder },
          { path: 'lab-results', Component: LabResults },
          { path: 'profile', Component: Profile },
          { path: 'messages', element: <Messages userRole="patient" userId="p1" /> },
        ],
      },

      // ─── Doctor ────────────────────────────────────────────────────────────
      {
        path: 'doctor',
        element: <DashboardLayout role="doctor" userName={CURRENT_USER_DOCTOR.name} />,
        children: [
          { index: true, element: <ProfessionalDashboard role="doctor" /> },
          { path: 'dashboard', element: <ProfessionalDashboard role="doctor" /> },
          { path: 'patients', Component: DoctorPatients },
          { path: 'patient/:id', Component: PatientWorkspace },
          { path: 'schedule', Component: DoctorSchedule },
          { path: 'reports', Component: DoctorReports },
          { path: 'messages', element: <Messages userRole="professional" userId="d1" /> },
        ],
      },

      // ─── Nurse ─────────────────────────────────────────────────────────────
      {
        path: 'nurse',
        element: <DashboardLayout role="nurse" userName="Nurse Anjali" />,
        children: [
          { index: true, element: <ProfessionalDashboard role="nurse" /> },
          { path: 'dashboard', element: <ProfessionalDashboard role="nurse" /> },
          { path: 'patients', Component: NursePatients },
          { path: 'care', Component: NursePatientCare },
          { path: 'rounds', Component: NurseRounds },
          { path: 'patient/:id', Component: PatientDetail },
          { path: 'messages', element: <Messages userRole="professional" userId="n1" /> },
        ],
      },

      // ─── Hospital ──────────────────────────────────────────────────────────
      {
        path: 'hospital',
        element: <DashboardLayout role="hospital" userName="Nawaloka Hospital" />,
        children: [
          { index: true, Component: HospitalDashboard },
          { path: 'dashboard', Component: HospitalDashboard },
          { path: 'lab', Component: LabManagement },
          { path: 'messages', element: <Messages userRole="professional" userId="h1" /> },
        ],
      },

      { path: '*', Component: NotFound },
    ],
  },
]);

/**
 * Professional Dashboard Header Component
 * 
 * This is an example of how to integrate NotificationBell into a real dashboard
 * with professional features like user menu, theme switcher, and notifications.
 */

import { useState } from 'react';
import { Bell, Settings, LogOut, User } from 'lucide-react';
import { NotificationBell } from './NotificationBell';
import { ThemeSwitcher } from './ThemeSwitcher';
import { mockNotifications, Notification } from '../lib/mockNotifications';
import { Button } from './ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from './ui/dropdown-menu';
import { Avatar, AvatarFallback, AvatarImage } from './ui/avatar';

interface ProfessionalHeaderProps {
  userName?: string;
  userEmail?: string;
  userAvatar?: string;
  onLogout?: () => void;
  onSettings?: () => void;
}

/**
 * Complete professional dashboard header with NotificationBell
 * Usage: Import this component and place it in your dashboard layout
 * 
 * <ProfessionalDashboardHeader
 *   userName="Dr. Emily Chen"
 *   userEmail="emily@hospital.com"
 *   onLogout={handleLogout}
 *   onSettings={handleSettings}
 * />
 */
export function ProfessionalDashboardHeader({
  userName = 'Professional',
  userEmail = 'user@icams.com',
  userAvatar,
  onLogout,
  onSettings,
}: ProfessionalHeaderProps) {
  const [notifications, setNotifications] =
    useState<Notification[]>(mockNotifications);

  const handleMarkAsRead = (notificationId: string) => {
    setNotifications((prev) =>
      prev.map((notif) =>
        notif.id === notificationId ? { ...notif, isRead: true } : notif
      )
    );
  };

  const handleNotificationClick = (notification: Notification) => {
    console.log('Notification clicked:', notification);
    // You can add navigation or action handling here
    // e.g., navigate to patient detail, open alert dialog, etc.
  };

  const getInitials = (name: string) => {
    return name
      .split(' ')
      .map((n) => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  return (
    <header className="sticky top-0 z-40 w-full border-b border-slate-200 bg-white dark:border-slate-800 dark:bg-slate-900 shadow-sm">
      <div className="flex h-16 items-center justify-between px-4 sm:px-6 lg:px-8">
        {/* Left side - Logo/Branding */}
        <div className="flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-gradient-to-br from-blue-600 to-cyan-600 text-white font-bold">
            IC
          </div>
          <h1 className="hidden sm:inline-block text-xl font-bold text-slate-900 dark:text-white">
            I-CAMS Dashboard
          </h1>
        </div>

        {/* Right side - Notifications, Theme, User Menu */}
        <div className="flex items-center gap-2 sm:gap-4">
          {/* Notifications */}
          <NotificationBell
            notifications={notifications}
            onMarkAsRead={handleMarkAsRead}
            onNotificationClick={handleNotificationClick}
          />

          {/* Theme Switcher */}
          <ThemeSwitcher />

          {/* Divider */}
          <div className="hidden h-8 w-px bg-slate-200 dark:bg-slate-700 sm:block" />

          {/* User Menu Dropdown */}
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="ghost"
                size="icon"
                className="relative h-10 w-10"
              >
                <Avatar className="h-10 w-10 cursor-pointer">
                  <AvatarImage src={userAvatar} alt={userName} />
                  <AvatarFallback className="bg-blue-600 text-white font-semibold">
                    {getInitials(userName)}
                  </AvatarFallback>
                </Avatar>
              </Button>
            </DropdownMenuTrigger>

            <DropdownMenuContent align="end" className="w-56">
              {/* User Info */}
              <div className="px-2 py-1.5">
                <p className="text-sm font-semibold text-slate-900 dark:text-white">
                  {userName}
                </p>
                <p className="text-xs text-slate-500 dark:text-slate-400">
                  {userEmail}
                </p>
              </div>

              <DropdownMenuSeparator />

              {/* Menu Items */}
              <DropdownMenuItem onClick={() => console.log('Profile')}>
                <User className="mr-2 h-4 w-4" />
                <span>View Profile</span>
              </DropdownMenuItem>

              <DropdownMenuItem onClick={onSettings}>
                <Settings className="mr-2 h-4 w-4" />
                <span>Settings</span>
              </DropdownMenuItem>

              <DropdownMenuSeparator />

              <DropdownMenuItem onClick={onLogout} className="text-red-600">
                <LogOut className="mr-2 h-4 w-4" />
                <span>Sign Out</span>
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </div>
    </header>
  );
}

/**
 * Minimal Header Version (for simple dashboards)
 * More compact alternative
 */
export function MinimalDashboardHeader() {
  const [notifications, setNotifications] =
    useState<Notification[]>(mockNotifications);

  return (
    <header className="flex h-14 items-center justify-between border-b bg-white px-4 dark:border-slate-800 dark:bg-slate-900">
      <h1 className="font-semibold text-slate-900 dark:text-white">Dashboard</h1>
      <div className="flex items-center gap-2">
        <NotificationBell
          notifications={notifications}
          onMarkAsRead={(id) => {
            setNotifications((prev) =>
              prev.map((n) => (n.id === id ? { ...n, isRead: true } : n))
            );
          }}
        />
        <ThemeSwitcher />
      </div>
    </header>
  );
}

/**
 * Integration Steps:
 * 
 * 1. In your main dashboard component or layout:
 *    import { ProfessionalDashboardHeader } from "@/app/components/DashboardHeader";
 *
 * 2. Handle state management for notifications:
 *    const [notifications, setNotifications] = useState(mockNotifications);
 *    
 *    useEffect(() => {
 *      // Fetch notifications from API
 *      const fetchNotifications = async () => {
 *        const response = await fetch("/api/notifications");
 *        const data = await response.json();
 *        setNotifications(data);
 *      };
 *      
 *      fetchNotifications();
 *      const interval = setInterval(fetchNotifications, 30000);
 *      return () => clearInterval(interval);
 *    }, []);
 *
 * 3. Add the header to your layout:
 *    <ProfessionalDashboardHeader
 *      userName={currentUser.name}
 *      userEmail={currentUser.email}
 *      userAvatar={currentUser.avatarUrl}
 *      onLogout={handleLogout}
 *      onSettings={handleSettings}
 *    />
 *
 * 4. Wrap your page content within the same provider for context state
 */

import { Link, Outlet, useLocation } from 'react-router';
import {
  LayoutDashboard,
  User,
  FileText,
  Bell,
  Settings,
  LogOut,
  Menu,
  X,
  Activity,
  Calendar,
  Users,
  MessageCircle,
  Building2,
  FlaskConical,
  ClipboardList,
  Stethoscope,
} from 'lucide-react';
import { useState, useEffect } from 'react';
import { clsx } from 'clsx';
import { MOCK_PATIENTS } from '../lib/mockData';
import { ThemeSwitcher } from './ThemeSwitcher';
import { NotificationBell } from './NotificationBell';
import { mockNotifications, Notification } from '../lib/mockNotifications';
import { checkAllPatientAlerts } from '../lib/alertGenerator';

export type UserRole = 'patient' | 'nurse' | 'doctor' | 'hospital';

interface DashboardLayoutProps {
  role: UserRole;
  userName: string;
}

export function DashboardLayout({ role, userName }: DashboardLayoutProps) {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const location = useLocation();

  // Initialize notifications from localStorage or mock data
  useEffect(() => {
    const savedNotifications = localStorage.getItem('notifications');
    if (savedNotifications) {
      try {
        const parsed = JSON.parse(savedNotifications);
        const loaded = parsed.map((n: Notification) => ({
          ...n,
          timestamp: new Date(n.timestamp)
        }));
        // Check for health log alerts and merge them
        const withHealthAlerts = checkAllPatientAlerts(MOCK_PATIENTS, loaded);
        setNotifications(withHealthAlerts);
      } catch {
        // Fall back to mock data if parsing fails
        const initialNotifications = checkAllPatientAlerts(MOCK_PATIENTS, mockNotifications);
        setNotifications(initialNotifications);
      }
    } else {
      // Generate initial alerts from health logs with mock notifications
      const initialNotifications = checkAllPatientAlerts(MOCK_PATIENTS, mockNotifications);
      setNotifications(initialNotifications);
    }
  }, []);

  // Automatic alert generation from health logs (every 30 seconds)
  useEffect(() => {
    const interval = setInterval(() => {
      setNotifications((prev) => {
        // Check for new alerts from health logs
        return checkAllPatientAlerts(MOCK_PATIENTS, prev);
      });
    }, 30000); // Check every 30 seconds

    return () => clearInterval(interval);
  }, []);

  // Save notifications to localStorage whenever they change
  useEffect(() => {
    if (notifications.length > 0) {
      localStorage.setItem('notifications', JSON.stringify(notifications));
    }
  }, [notifications]);

  // Handle marking notification as read
  const handleMarkAsRead = (notificationId: string) => {
    setNotifications((prev) =>
      prev.map((notif) =>
        notif.id === notificationId ? { ...notif, isRead: true } : notif
      )
    );
  };

  // Handle notification click
  const handleNotificationClick = (notification: Notification) => {
    console.log('Notification clicked:', notification);
    // You can add navigation or other actions here based on notification type
  };

  const patientLinks = [
    { name: 'Dashboard', href: '/patient/dashboard', icon: LayoutDashboard },
    { name: 'Health Log', href: '/patient/log', icon: FileText },
    { name: 'Appointments', href: '/patient/appointments', icon: Calendar },
    { name: 'Find Hospitals', href: '/patient/hospitals', icon: Building2 },
    { name: 'Lab Results', href: '/patient/lab-results', icon: FlaskConical },
    { name: 'Messages', href: '/patient/messages', icon: MessageCircle },
    { name: 'Profile', href: '/patient/profile', icon: User },
  ];

  const doctorLinks = [
    { name: 'Dashboard', href: '/doctor/dashboard', icon: LayoutDashboard },
    { name: 'My Patients', href: '/doctor/patients', icon: Users },
    { name: 'Messages', href: '/doctor/messages', icon: MessageCircle },
    { name: 'Schedule', href: '/doctor/schedule', icon: Calendar },
    { name: 'Reports', href: '/doctor/reports', icon: FileText },
  ];

  const nurseLinks = [
    { name: 'Dashboard', href: '/nurse/dashboard', icon: LayoutDashboard },
    { name: 'Patients', href: '/nurse/patients', icon: Users },
    { name: 'Patient Care', href: '/nurse/care', icon: ClipboardList },
    { name: 'Messages', href: '/nurse/messages', icon: MessageCircle },
    { name: 'Rounds', href: '/nurse/rounds', icon: Activity },
  ];

  const hospitalLinks = [
    { name: 'Dashboard', href: '/hospital/dashboard', icon: LayoutDashboard },
    { name: 'Messages', href: '/hospital/messages', icon: MessageCircle },
  ];

  const links = role === 'patient' ? patientLinks
    : role === 'doctor' ? doctorLinks
      : role === 'nurse' ? nurseLinks
        : hospitalLinks;

  const userId = sessionStorage.getItem('userId') || 'default-id';

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex">
      {/* Mobile Sidebar Overlay */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 z-40 bg-slate-600 bg-opacity-75 dark:bg-slate-950 dark:bg-opacity-80 md:hidden"
          onClick={() => setSidebarOpen(false)}
        ></div>
      )}

      {/* Sidebar */}
      <div className={clsx(
        'fixed inset-y-0 left-0 z-50 w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transform transition-transform duration-300 ease-in-out md:translate-x-0 md:sticky md:top-0 md:h-screen md:inset-auto',
        sidebarOpen ? 'translate-x-0' : '-translate-x-full'
      )}>
        <div className="flex items-center justify-center h-16 border-b border-slate-200 dark:border-slate-800">
          <Link to="/" className="flex items-center gap-2 px-4">
            <Activity className="h-8 w-8 text-blue-600 dark:text-blue-500" />
            <span className="font-bold text-xl text-slate-900 dark:text-white">I-CAMS</span>
          </Link>
        </div>

        <div className="flex flex-col flex-grow pt-5 pb-4 overflow-y-auto">
          <nav className="mt-5 flex-1 px-2 space-y-1">
            {links.map((item) => {
              const isActive = location.pathname === item.href;
              return (
                <Link
                  key={item.name}
                  to={item.href}
                  onClick={() => setSidebarOpen(false)}
                  className={clsx(
                    isActive
                      ? 'bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 border-r-4 border-blue-600'
                      : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-slate-900 dark:hover:text-slate-300',
                    'group flex items-center px-2 py-2 text-sm font-medium rounded-md transition-colors duration-200'
                  )}
                >
                  <item.icon
                    className={clsx(
                      isActive ? 'text-blue-600 dark:text-blue-400' : 'text-slate-400 dark:text-slate-500 group-hover:text-slate-500 dark:group-hover:text-slate-400',
                      'mr-3 flex-shrink-0 h-6 w-6'
                    )}
                  />
                  {item.name}
                </Link>
              );
            })}
          </nav>
        </div>

        <div className="flex-shrink-0 flex border-t border-slate-200 dark:border-slate-800 p-4">
          <div className="flex-shrink-0 w-full group block">
            <div className="flex items-center">
              <div className="h-9 w-9 rounded-full bg-slate-200 dark:bg-slate-700 flex items-center justify-center text-slate-500 dark:text-slate-400">
                <User size={20} />
              </div>
              <div className="ml-3">
                <p className="text-sm font-medium text-slate-700 dark:text-slate-300 group-hover:text-slate-900 dark:group-hover:text-white transition-colors duration-200">
                  {userName}
                </p>
                <p className="text-xs font-medium text-slate-500 dark:text-slate-400 group-hover:text-slate-700 dark:group-hover:text-slate-300 capitalize transition-colors duration-200">
                  {role}
                </p>
              </div>
            </div>
            <Link to="/login" className="mt-4 flex items-center text-sm text-red-600 dark:text-red-500 hover:text-red-800 dark:hover:text-red-400 transition-colors duration-200">
              <LogOut className="h-4 w-4 mr-2" />
              Sign Out
            </Link>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Top Header */}
        <div className="flex items-center justify-between bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 px-4 py-3 h-16">
          {/* Left side - Mobile menu toggle */}
          <button
            onClick={() => setSidebarOpen(true)}
            className="md:hidden -ml-0.5 h-10 w-10 inline-flex items-center justify-center rounded-md text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-300 focus:outline-none focus:ring-2 focus:ring-inset focus:ring-blue-500 transition-colors duration-200"
          >
            <span className="sr-only">Open sidebar</span>
            <Menu className="h-6 w-6" />
          </button>

          {/* Center - Page title (mobile) */}
          <div className="md:hidden font-semibold text-slate-900 dark:text-white text-sm">Dashboard</div>

          {/* Right side - Notifications, Theme, etc */}
          <div className="flex items-center gap-2 ml-auto md:ml-0">
            <NotificationBell
              notifications={notifications}
              onMarkAsRead={handleMarkAsRead}
              onNotificationClick={handleNotificationClick}
            />
            <ThemeSwitcher />
          </div>
        </div>

        {/* Page Content */}
        <main className="flex-1 overflow-y-auto focus:outline-none p-6">
          <div className="max-w-7xl mx-auto">
            <Outlet />
          </div>
        </main>
      </div>
    </div>
  );
}

import React from 'react';
import { AlertCircle, CheckCircle, AlertTriangle } from 'lucide-react';

export type SeverityLevel = 'stable' | 'moderate' | 'critical';

export interface StatusBadgeProps {
  /**
   * Numeric severity value (0-10 scale)
   * 0-3: Stable (Green)
   * 4-7: Moderate (Yellow)
   * 8-10: Critical (Red)
   */
  severity: number;

  /**
   * Optional custom label to override auto-generated label
   */
  label?: string;

  /**
   * Optional size variant
   * @default 'md'
   */
  size?: 'sm' | 'md' | 'lg';

  /**
   * Whether to show icon
   * @default true
   */
  showIcon?: boolean;

  /**
   * Optional className for custom styling
   */
  className?: string;

  /**
   * Optional callback when badge is clicked
   */
  onClick?: () => void;
}

/**
 * Get severity level from numeric value
 * @param severity Numeric value 0-10
 * @returns Severity level: 'stable' | 'moderate' | 'critical'
 */
export const getSeverityLevel = (severity: number): SeverityLevel => {
  if (severity <= 3) return 'stable';
  if (severity <= 7) return 'moderate';
  return 'critical';
};

/**
 * Get color styling based on severity
 */
const getSeverityColors = (level: SeverityLevel) => {
  switch (level) {
  case 'stable':
    return {
      bg: 'bg-green-100 dark:bg-green-900/30',
      text: 'text-green-800 dark:text-green-300',
      border: 'border-green-300 dark:border-green-700',
      dot: 'bg-green-500',
      label: 'Stable',
    };
  case 'moderate':
    return {
      bg: 'bg-yellow-100 dark:bg-yellow-900/30',
      text: 'text-yellow-800 dark:text-yellow-300',
      border: 'border-yellow-300 dark:border-yellow-700',
      dot: 'bg-yellow-500',
      label: 'Moderate',
    };
  case 'critical':
    return {
      bg: 'bg-red-100 dark:bg-red-900/30',
      text: 'text-red-800 dark:text-red-300',
      border: 'border-red-300 dark:border-red-700',
      dot: 'bg-red-500',
      label: 'Critical',
    };
  default:
    return {
      bg: 'bg-gray-100 dark:bg-gray-800',
      text: 'text-gray-800 dark:text-gray-300',
      border: 'border-gray-300 dark:border-gray-600',
      dot: 'bg-gray-500',
      label: 'Unknown',
    };
  }
};

/**
 * Get icon based on severity
 */
const getSeverityIcon = (level: SeverityLevel) => {
  switch (level) {
  case 'stable':
    return <CheckCircle className="w-full h-full" />;
  case 'moderate':
    return <AlertTriangle className="w-full h-full" />;
  case 'critical':
    return <AlertCircle className="w-full h-full" />;
  default:
    return null;
  }
};

/**
 * Get size classes
 */
const getSizeClasses = (size: 'sm' | 'md' | 'lg') => {
  switch (size) {
  case 'sm':
    return {
      container: 'px-2 py-1 text-xs',
      icon: 'w-3 h-3',
    };
  case 'md':
    return {
      container: 'px-3 py-1.5 text-sm',
      icon: 'w-4 h-4',
    };
  case 'lg':
    return {
      container: 'px-4 py-2 text-base',
      icon: 'w-5 h-5',
    };
  default:
    return {
      container: 'px-3 py-1.5 text-sm',
      icon: 'w-4 h-4',
    };
  }
};

/**
 * StatusBadge Component
 *
 * A reusable status indicator that displays health status based on severity
 *
 * @example
 * // Basic usage with numeric severity
 * <StatusBadge severity={8} />  // Shows "Critical" in red
 *
 * @example
 * // With custom label
 * <StatusBadge severity={5} label="Needs Monitoring" />
 *
 * @example
 * // Different sizes
 * <StatusBadge severity={2} size="sm" />   // Small
 * <StatusBadge severity={5} size="md" />   // Medium (default)
 * <StatusBadge severity={9} size="lg" />   // Large
 *
 * @example
 * // Without icon
 * <StatusBadge severity={3} showIcon={false} />
 */
export const StatusBadge: React.FC<StatusBadgeProps> = ({
  severity,
  label: customLabel,
  size = 'md',
  showIcon = true,
  className = '',
  onClick,
}) => {
  // Clamp severity between 0 and 10
  const clampedSeverity = Math.max(0, Math.min(10, severity));
  const level = getSeverityLevel(clampedSeverity);
  const colors = getSeverityColors(level);
  const sizeClasses = getSizeClasses(size);
  const label = customLabel || colors.label;
  const icon = getSeverityIcon(level);

  const baseStyles = `
    inline-flex items-center gap-2 font-semibold rounded-full
    border transition-all duration-200
    ${colors.bg} ${colors.text} ${colors.border}
    ${sizeClasses.container}
    ${onClick ? 'cursor-pointer hover:shadow-md active:scale-95' : ''}
    ${className}
  `.trim();

  return (
    <button
      onClick={onClick}
      disabled={!onClick}
      className={baseStyles}
      title={`Severity: ${clampedSeverity}/10 - ${level}`}
    >
      {showIcon && (
        <div className={`flex-shrink-0 ${sizeClasses.icon} text-current`}>
          {icon}
        </div>
      )}
      <span className="whitespace-nowrap">{label}</span>
    </button>
  );
};

/**
 * StatusIndicator - A compact dot indicator without label
 */
export interface StatusIndicatorProps {
  severity: number;
  size?: 'sm' | 'md' | 'lg';
  animated?: boolean;
}

export const StatusIndicator: React.FC<StatusIndicatorProps> = ({
  severity,
  size = 'md',
  animated = false,
}) => {
  const clampedSeverity = Math.max(0, Math.min(10, severity));
  const level = getSeverityLevel(clampedSeverity);
  const colors = getSeverityColors(level);

  const sizeMap = {
    sm: 'w-2 h-2',
    md: 'w-3 h-3',
    lg: 'w-4 h-4',
  };

  const animationClass = animated && level === 'critical' ? 'animate-pulse' : '';

  return (
    <div
      className={`${sizeMap[size]} rounded-full ${colors.dot} ${animationClass}`}
      title={`Status: ${level}`}
    />
  );
};

/**
 * StatusRow - Combined indicator and badge
 */
export interface StatusRowProps {
  severity: number;
  label?: string;
  size?: 'sm' | 'md' | 'lg';
  animated?: boolean;
}

export const StatusRow: React.FC<StatusRowProps> = ({
  severity,
  label: customLabel,
  size = 'md',
  animated = false,
}) => {
  return (
    <div className="flex items-center gap-2">
      <StatusIndicator severity={severity} size={size} animated={animated} />
      <StatusBadge severity={severity} label={customLabel} size={size} showIcon={false} />
    </div>
  );
};

export default StatusBadge;

