import { createContext, useContext, useEffect, useState, ReactNode } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
  setTheme: (theme: Theme) => void;
}

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setThemeState] = useState<Theme>('light');
  const [isLoaded, setIsLoaded] = useState(false);

  // Initialize theme from localStorage or system preference
  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as Theme | null;

    if (savedTheme) {
      setThemeState(savedTheme);
      applyTheme(savedTheme);
    } else {
      // Check system preference
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      const initialTheme: Theme = prefersDark ? 'dark' : 'light';
      setThemeState(initialTheme);
      applyTheme(initialTheme);
    }

    setIsLoaded(true);
  }, []);

  const applyTheme = (newTheme: Theme) => {
    const htmlElement = document.documentElement;

    if (newTheme === 'dark') {
      htmlElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      htmlElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  };

  const setTheme = (newTheme: Theme) => {
    setThemeState(newTheme);
    applyTheme(newTheme);
  };

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
}

import { Notification, NotificationStatus } from './mockNotifications';
import { HealthLog, Patient } from './mockData';

/**
 * Generates health alerts based on pain level from health logs
 * 
 * Alert Rules:
 * - painLevel > 7: "High Risk" alert (status: "High")
 * - painLevel 4-7: "Moderate Risk" alert (status: "Moderate")
 * - painLevel < 4: No alert
 */

export const generateHealthAlerts = (patient: Patient, existingNotifications: Notification[]): Notification[] => {
  const newAlerts: Notification[] = [];

  // Get the most recent health log
  if (patient.logs && patient.logs.length > 0) {
    const latestLog = patient.logs[0]; // Most recent log (index 0)
    const painLevel = latestLog.painLevel ?? 0;

    // Generate unique alert ID based on patient and log
    const alertId = `pain-alert-${patient.id}-${latestLog.date}`;

    // Check if alert for this log already exists
    const alertExists = existingNotifications.some(n => n.id === alertId);

    // High Risk: painLevel > 7
    if (painLevel > 7) {
      if (!alertExists) {
        newAlerts.push({
          id: alertId,
          patientName: patient.name,
          message: `⚠️ HIGH RISK: Patient reported severe pain level of ${painLevel}/10. Immediate attention recommended.`,
          timestamp: new Date(latestLog.date),
          status: 'High',
          isRead: false,
        });
      }
    }
    // Moderate Risk: painLevel between 4-7
    else if (painLevel >= 4 && painLevel <= 7) {
      if (!alertExists) {
        newAlerts.push({
          id: alertId,
          patientName: patient.name,
          message: `📌 MODERATE RISK: Patient reported moderate pain level of ${painLevel}/10. Monitor closely.`,
          timestamp: new Date(latestLog.date),
          status: 'Moderate',
          isRead: false,
        });
      }
    }
    // Low/No Risk: painLevel < 4
    // No alert generated
  }

  return newAlerts;
};

/**
 * Merges generated alerts with existing notifications
 * Prevents duplicates and maintains read status
 */
export const mergeAlerts = (
  existingNotifications: Notification[],
  generatedAlerts: Notification[]
): Notification[] => {
  // Filter out old alerts for the same patients/logs
  const filtered = existingNotifications.filter(n => !n.id.startsWith('pain-alert-'));

  // Add generated alerts only if they don't exist
  const merged = [...generatedAlerts, ...filtered];

  // Remove duplicates (by ID)
  const seen = new Set<string>();
  return merged.filter(n => {
    if (seen.has(n.id)) return false;
    seen.add(n.id);
    return true;
  });
};

/**
 * Check all patients and generate alerts from their latest health logs
 */
export const checkAllPatientAlerts = (
  patients: Patient[],
  existingNotifications: Notification[]
): Notification[] => {
  let allAlerts: Notification[] = [];

  // Generate alerts for each patient
  for (const patient of patients) {
    const patientAlerts = generateHealthAlerts(patient, existingNotifications);
    allAlerts = [...allAlerts, ...patientAlerts];
  }

  // Merge with existing notifications
  return mergeAlerts(existingNotifications, allAlerts);
};

/**
 * Format pain level into a readable risk category
 */
export const getPainRiskCategory = (painLevel: number = 0): {
  category: string;
  severity: NotificationStatus;
  description: string;
} => {
  if (painLevel > 7) {
    return {
      category: 'HIGH RISK',
      severity: 'High',
      description: `Severe pain level: ${painLevel}/10 - Requires immediate attention`,
    };
  } else if (painLevel >= 4) {
    return {
      category: 'MODERATE RISK',
      severity: 'Moderate',
      description: `Moderate pain level: ${painLevel}/10 - Monitor closely`,
    };
  } else {
    return {
      category: 'LOW RISK',
      severity: 'Normal',
      description: `Low pain level: ${painLevel}/10 - No immediate concern`,
    };
  }
};

/**
 * Health Status Calculation Utilities
 * 
 * Functions to calculate health status indicators from health log data
 */

import { HealthLog } from './mockData';

/**
 * Calculate overall health severity from painLevel and symptoms
 * 
 * Scoring:
 * - painLevel: 0-10 (direct mapping)
 * - Symptoms: each symptom adds points
 * 
 * Severity Range: 0-10 (for StatusBadge compatibility)
 */
export const calculateHealthSeverity = (log: HealthLog): number => {
  let severity = 0;

  // Start with pain level (0-10)
  if (log.painLevel !== undefined) {
    severity = log.painLevel;
  }

  // Add severity based on symptom count
  // Each symptom adds 1-2 points depending on the symptom type
  if (log.symptoms && log.symptoms.length > 0) {
    const criticalSymptoms = ['Chest Pain', 'Difficulty Breathing', 'Severe Headache', 'Loss of Consciousness', 'Uncontrollable Bleeding'];
    const moderateSymptoms = ['Moderate Pain', 'Dizziness', 'Nausea', 'Vomiting', 'Shortness of Breath'];

    for (const symptom of log.symptoms) {
      if (criticalSymptoms.includes(symptom)) {
        severity += 3; // Add 3 points for critical symptoms
      } else if (moderateSymptoms.includes(symptom)) {
        severity += 1.5; // Add 1.5 points for moderate symptoms
      } else {
        severity += 1; // Add 1 point for other symptoms
      }
    }
  }

  // Cap severity at 10
  return Math.min(severity, 10);
};

/**
 * Get a descriptive label for the health status
 */
export const getHealthStatusLabel = (severity: number): string => {
  if (severity <= 3) {
    return 'Stable';
  } else if (severity <= 7) {
    return 'Monitoring';
  } else {
    return 'Critical';
  }
};

/**
 * Get symptom severity level (for additional context)
 */
export const getSymptomSeverity = (symptoms: string[]): 'none' | 'mild' | 'moderate' | 'severe' => {
  if (!symptoms || symptoms.length === 0) {
    return 'none';
  }

  const criticalSymptoms = ['Chest Pain', 'Difficulty Breathing', 'Severe Headache', 'Loss of Consciousness', 'Uncontrollable Bleeding'];
  const moderateSymptoms = ['Moderate Pain', 'Dizziness', 'Nausea', 'Vomiting', 'Shortness of Breath'];

  const hasCritical = symptoms.some(s => criticalSymptoms.includes(s));
  const hasModerate = symptoms.some(s => moderateSymptoms.includes(s));

  if (hasCritical) {
    return 'severe';
  } else if (hasModerate || symptoms.length > 2) {
    return 'moderate';
  } else {
    return 'mild';
  }
};

/**
 * Generate a tooltip/description for health status
 */
export const getHealthStatusDescription = (log: HealthLog): string => {
  const severity = calculateHealthSeverity(log);
  const symptomSeverity = getSymptomSeverity(log.symptoms);

  if (severity <= 3) {
    return 'Patient is stable with normal vitals';
  } else if (severity <= 7) {
    return `Patient requires monitoring - ${log.symptoms.length > 0 ? `${log.symptoms.length} symptom(s) reported` : 'vital changes noted'}`;
  } else {
    return 'Critical condition - Immediate attention required';
  }
};

