                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-slate-500 dark:text-slate-400">{patient.condition}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
