  patientName: string;
  patientAge: number;
  reportType: 'lab-results' | 'diagnostic-imaging' | 'clinical-summary' | 'progress-note' | 'discharge-summary';
  date: string;
  status: 'pending' | 'completed' | 'reviewed';
